    const handleDownload = (format: 'xlsx' | 'pdf', groupData?: { groupName: string; results: MatchResult[]; reportType: 'income' | 'expenses' }) => {
        const dataToExport = groupData ? [groupData] : [{ groupName, results: processedResults, reportType }];
